sql:
SELECT COUNT(*) AS num_shiny_forms
FROM pokemon_forms
WHERE is_shiny = 1;

SELECT pokemon_id, COUNT(*) AS num_forms
FROM pokemon_forms
GROUP BY pokemon_id;

SELECT * 
FROM pokemon_forms 
WHERE is_shiny = 1;

SELECT trainer_id, COUNT(item_id) AS item_count
FROM item_usage
GROUP BY trainer_id;

SELECT DISTINCT p.pokemon_name, p.description
FROM pokemon p
JOIN pokemon_ownership po ON p.pokemon_id = po.pokemon_id;

SELECT pokemon_name
FROM pokemon
WHERE (SELECT AVG(weight) FROM pokemon) > 10;

SELECT form_name
FROM pokemon_forms
WHERE is_shiny = 1;

SELECT * 
FROM training_plans 
WHERE plan_status = 'Active';
